import java.util.Scanner;
import java.nio.charset.StandardCharsets;

public class SecureBufferHandling {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");
        String input = scanner.nextLine();

        // Check if input exceeds buffer size
        if (input.length() > 10) {
            System.out.println("Input exceeds buffer size. Please enter a shorter name.");
            return;
        }

        // Use a safe method to convert String to byte array
        byte[] buffer = input.getBytes(StandardCharsets.UTF_8);

        System.out.println("Hello, " + new String(buffer, StandardCharsets.UTF_8));
    }
}

### Explanation:
취약유형: Buffer Overflow
